// Normaliza payload independentemente de onde o body veio
const b = $input.item.json.body ?? $input.item.json;
return [{ json: {
  campanha_id:         b.campanha_id,
  viagem_id:           b.viagem_id ?? null,
  segmento:            b.segmento,
  mensagem:            b.mensagem,
  imagem_url:          b.imagem_url ?? null,
  audio_url:           b.audio_url ?? null,
  delay_segundos:      Number(b.delay_segundos ?? 3),
  limite:              Number(b.limite_por_execucao ?? 50),
} }];

// ── Buscar contatos elegíveis no Supabase conforme o segmento
// Variáveis de ambiente necessárias no n8n:
//   SUPABASE_URL           — Project URL
//   SUPABASE_SERVICE_ROLE  — Service Role Key (acesso admin)
// ─────────────────────────────────────────────────────────

const { campanha_id, viagem_id, segmento, mensagem, delay_segundos, limite, imagem_url, audio_url } = $input.item.json;

const BASE    = $('Config Supabase').first().json.SUPABASE_URL + '/rest/v1';
const KEY     = $('Config Supabase').first().json.SUPABASE_SERVICE_ROLE;
const HEADERS   = { 'apikey': KEY, 'Authorization': `Bearer ${KEY}` };

const httpRequest = this.helpers.httpRequest;

async function get(url) {
  return await httpRequest({
    method: 'GET',
    url,
    headers: HEADERS,
    json: true,
  });
}

// ── Buscar viagem ──────────────────────────────────────────
let viagem = { titulo: '', destino: '', data_saida: '', valor: '', link_publico: '' };
if (viagem_id) {
  const rows = await get(`${BASE}/viagens?id=eq.${viagem_id}&select=titulo,destino,data_saida,valor,link_publico&limit=1`);
  if (rows[0]) viagem = rows[0];
}

// ── Query por segmento ─────────────────────────────────────
const OPT_FILTER = 'opt_out=eq.false&aceitou_receber_mensagens=eq.true';
const LIMIT_QS   = `limit=${limite}`;
let rawRows = [];
const isLead = ['leads_novos', 'leads_nao_convertidos', 'viagem_especifica'].includes(segmento);

switch (segmento) {
  case 'todos_contatos': {
    const [clientes, leads] = await Promise.all([
      get(`${BASE}/clientes?${OPT_FILTER}&select=id,nome,whatsapp,cidade&${LIMIT_QS}`),
      get(`${BASE}/leads?status=in.(novo,contatado,negociando)&select=id,nome,whatsapp,cidade&${LIMIT_QS}`),
    ]);
    clientes.forEach(c => c.origem_tabela = 'clientes');
    leads.forEach(l => l.origem_tabela = 'leads');

    // Deduplica por WhatsApp — cliente tem prioridade
    const vistos = new Set(clientes.map(c => {
      let nr = (c.whatsapp || '').replace(/\D/g, '');
      if (nr.length === 10 || nr.length === 11) nr = '55' + nr;
      else if (nr.length > 11 && !nr.startsWith('55')) nr = '55' + nr;
      return nr;
    }));

    const leadsNovos = leads.filter(l => {
      let nr = (l.whatsapp || '').replace(/\D/g, '');
      if (nr.length === 10 || nr.length === 11) nr = '55' + nr;
      else if (nr.length > 11 && !nr.startsWith('55')) nr = '55' + nr;
      return !vistos.has(nr);
    });

    rawRows = [...clientes, ...leadsNovos];
    break;
  }
  case 'lista_vip':
    rawRows = await get(`${BASE}/clientes?${OPT_FILTER}&origem=eq.lista_vip&select=id,nome,whatsapp,cidade&${LIMIT_QS}`);
    break;
  case 'todos_clientes':
    rawRows = await get(`${BASE}/clientes?${OPT_FILTER}&select=id,nome,whatsapp,cidade&${LIMIT_QS}`);
    break;
  case 'leads_novos':
    rawRows = await get(`${BASE}/leads?status=eq.novo&select=id,nome,whatsapp,cidade&${LIMIT_QS}`);
    break;
  case 'leads_nao_convertidos':
    rawRows = await get(`${BASE}/leads?status=in.(novo,contatado,negociando)&select=id,nome,whatsapp,cidade&${LIMIT_QS}`);
    break;
  case 'viagem_especifica':
    if (!viagem_id) { rawRows = []; break; }
    rawRows = await get(`${BASE}/leads?viagem_id=eq.${viagem_id}&select=id,nome,whatsapp,cidade&${LIMIT_QS}`);
    break;
  default:
    if (segmento.startsWith('categoria_')) {
      const cat = segmento.replace('categoria_', '');
      rawRows = await get(`${BASE}/clientes?${OPT_FILTER}&categoria_favorita=eq.${cat}&select=id,nome,whatsapp,cidade&${LIMIT_QS}`);
    }
}

// ── Buscar números com Opt-Out para exclusão ─────────────────
const optOutRows = await get(`${BASE}/clientes?opt_out=eq.true&select=whatsapp`);
const optOutSet = new Set(optOutRows.map(r => {
  let nr = (r.whatsapp || '').replace(/\D/g, '');
  if (nr.length === 10 || nr.length === 11) {
    nr = '55' + nr;
  } else if (nr.length > 11 && !nr.startsWith('55')) {
    nr = '55' + nr;
  }
  return nr;
}));

// ── Formatar data de saída ─────────────────────────────────
const fmtData = (d) => {
  if (!d) return '';
  const [year, month, day] = d.split('-');
  const meses = ['jan','fev','mar','abr','mai','jun','jul','ago','set','out','nov','dez'];
  return `${parseInt(day)} de ${meses[parseInt(month)-1]} de ${year}`;
};

// ── Normalizar e deduplicar ────────────────────────────────
const seen = new Set();
const contatos = rawRows
  .map(c => {
    let nr = (c.whatsapp || '').replace(/\D/g, '');
    if (nr.length === 10 || nr.length === 11) {
      nr = '55' + nr;
    } else if (nr.length > 11 && !nr.startsWith('55')) {
      nr = '55' + nr;
    }
    return {
      cliente_id:         c.origem_tabela === 'leads' || isLead ? null : c.id,
      nome:               c.nome,
      whatsapp:           nr,
      cidade:             c.cidade ?? '',
      campanha_id,
      mensagem_template:  mensagem,
      delay_segundos,
      viagem_titulo:      viagem.titulo,
      viagem_destino:     viagem.destino,
      viagem_data_fmt:    fmtData(viagem.data_saida),
      viagem_valor:       viagem.valor ? `R$ ${Number(viagem.valor).toLocaleString('pt-BR', {minimumFractionDigits:2})}` : '',
      viagem_link:        viagem.link_publico ?? '',
      imagem_url:         imagem_url ?? null,
      audio_url:          audio_url ?? null,
    };
  })
  .filter(c => c.whatsapp.length >= 10)
  .filter(c => !optOutSet.has(c.whatsapp))
  .filter(c => { if (seen.has(c.whatsapp)) return false; seen.add(c.whatsapp); return true; });

if (contatos.length === 0) {
  return [{ json: { _sem_contatos: true, campanha_id } }];
}

return contatos.map(c => ({ json: c }));

const j = $json;

const msg = (j.mensagem_template || '')
  .replace(/\{\{nome\}\}/g, j.nome || 'amigo(a)')
  .replace(/\{\{destino\}\}/g, j.viagem_destino || '')
  .replace(/\{\{data_saida\}\}/g, j.viagem_data_fmt || '')
  .replace(/\{\{valor\}\}/g, j.viagem_valor || '')
  .replace(/\{\{link_viagem\}\}/g, j.viagem_link || '');

return {
  ...j,
  mensagem_final: msg,
};

const { whatsapp, mensagem_final, imagem_url, audio_url } = $input.item.json;

const EVOLUTION_URL      = $('Config Evolution').first().json.EVOLUTION_API_URL;
const EVOLUTION_INSTANCE = $('Config Evolution').first().json.EVOLUTION_INSTANCE;
const EVOLUTION_KEY      = $('Config Evolution').first().json.EVOLUTION_API_KEY;

const headers    = { 'apikey': EVOLUTION_KEY, 'Content-Type': 'application/json' };
const httpRequest = this.helpers.httpRequest;

let response;
try {
  if (imagem_url) {
    response = await httpRequest({
      method: 'POST',
      url: `${EVOLUTION_URL}/message/sendMedia/${EVOLUTION_INSTANCE}`,
      headers,
      body: { number: whatsapp, mediatype: 'image', media: imagem_url, caption: mensagem_final },
      json: true,
    });
  } else {
    response = await httpRequest({
      method: 'POST',
      url: `${EVOLUTION_URL}/message/sendText/${EVOLUTION_INSTANCE}`,
      headers,
      body: { number: whatsapp, text: mensagem_final },
      json: true,
    });
  }
} catch (e) {
  response = { error: e.message };
}

if (audio_url && !response.error) {
  try {
    await httpRequest({
      method: 'POST',
      url: `${EVOLUTION_URL}/message/sendWhatsAppAudio/${EVOLUTION_INSTANCE}`,
      headers,
      body: { number: whatsapp, audio: audio_url },
      json: true,
    });
  } catch (e) {
    console.error('Failed to send audio:', e.message);
  }
}

return [{ json: response }];

// Salva o resultado do envio no Supabase
const response = $input.item.json;
const contact = $('Montar Mensagem').item.json;

const BASE  = $('Config Supabase').first().json.SUPABASE_URL + '/rest/v1';
const KEY   = $('Config Supabase').first().json.SUPABASE_SERVICE_ROLE;

const ok = !response.error && response.key?.id !== undefined;
const status = ok ? 'enviado' : 'erro';
const messageId = response.key?.id || null;

const httpRequest = this.helpers.httpRequest;

try {
  await httpRequest({
    method: 'POST',
    url: `${BASE}/mensagens_whatsapp`,
    headers: {
      'apikey': KEY,
      'Authorization': `Bearer ${KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal',
    },
    body: {
      campanha_id:  contact.campanha_id,
      cliente_id:   contact.cliente_id ?? null,
      whatsapp:     contact.whatsapp,
      mensagem:     contact.mensagem_final,
      status_envio: status,
      resposta_api: ok ? response : null,
      enviado_em:   ok ? new Date().toISOString() : null,
      erro:         ok ? null : (response.message || JSON.stringify(response)),
    },
    json: true
  });
} catch (e) {
  console.error('Error saving message log:', e.message);
}

return [{ json: { ...contact, ...response, _status_envio: status, _id_mensagem: messageId } }];

const contact = $('Montar Mensagem').first().json;
const campanha_id = $input.first().json.campanha_id || contact.campanha_id;

const BASE = $('Config Supabase').first().json.SUPABASE_URL + '/rest/v1';
const KEY = $('Config Supabase').first().json.SUPABASE_SERVICE_ROLE;

const httpRequest = this.helpers.httpRequest;

let total = 0;
try {
  const response = await httpRequest({
    method: 'GET',
    url: `${BASE}/mensagens_whatsapp?campanha_id=eq.${campanha_id}&status_envio=eq.enviado&select=id`,
    headers: {
      'apikey': KEY,
      'Authorization': `Bearer ${KEY}`
    },
    json: true
  });

  total = Array.isArray(response) ? response.length : 0;

  await httpRequest({
    method: 'PATCH',
    url: `${BASE}/campanhas_whatsapp?id=eq.${campanha_id}`,
    headers: {
      'apikey': KEY,
      'Authorization': `Bearer ${KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal',
    },
    body: { total_enviados: total },
    json: true
  });
} catch (e) {
  console.error('Error updating campaign status:', e.message);
}

return [{ json: { campanha_id, total_enviados: total } }];
